后缀数组 + 主席树上二分后缀数组练习题


题意已知字符串 $s$ 。$m$ 次询问，每次询问串 $s$ 中子串 $s[c…d]$ 与子串 $s[a…b]$ 中每个子串的 $lcp$ 的最大值。
思路由于字符串 $s$ 是给定的，可以预处理出 $s$ 的后缀数组，从而可以 $O(1)$ 地求出某两个后缀的 $lcp$ 长度。很容易发现答案具有二分性，可以二分出 $lcp$ 的长度从而转换为存在性问题。假设当前二分的结果是 $mid$ ，可以发现 只有起点位于 $[a…b-mid+1]$ 内的后缀与 $s[c…d]$ 的 $lcp$ 长度可能 $\geq mid$ ，所以问题即转换为求 $[a…b-mid+1]$ 内的后缀与后缀 $c$ 的$lcp$。因为是多组询问，不可能每一次都将 $c$ 与 $[a…b-mid+1]$ 中的每一个后缀比较一次。考虑后缀数组的性质，以后缀排名为下标， $[a…b-mid+1]$ 中的所有后缀与后缀 $c$ 放置在数轴上是一系列散点，假设后缀 $c$ 在所有后缀中的排名为 $x$ ，可以发现只需要计算 $x$ 左右最近的两个位置与它的 $lcp$ 即可。具体实现时，可以对串 $s$ 以后缀排名为下标可持久化，单次询问需要查询 $x$ 左右的第一个 $1$ 的位置，查询一次复杂度为 $O(logn)$ 。所以处理一次询问的复杂度为 $O(log^2n)$ 。预处理 $+$ 询问的总复杂度为 $O(n \cdot log^2n)$ 。
Code:#include&lt;bits/stdc++.h>
using namespace std;

using ll=long long;
using pii=pair&lt;int,int>;

constexpr int N=1e5+5;

int n,m;
int a,b,c,d;
struct SA&#123;
    int n,m;
    char s[N];
    int sa[N],rk[N],height[N],h[N];
    int minn[21][N],lg[N];
    void init(int _n,int _m)&#123;
        n=_n;
        m=_m;
    &#125;
    void buildsa()&#123;
        static int oldrk[N&lt;&lt;1],id[N],px[N],cnt[N];
        int i,p,w;
        for(i=1;i&lt;=m+1;i++) cnt[i]=0;
        for(i=1;i&lt;=n+1;++i) sa[i]=rk[i]=id[i]=px[i]=0;
        for(i=1;i&lt;=n*2;i++) oldrk[i]=0;
        for(i=1;i&lt;=n;++i) ++cnt[rk[i]=(s[i]-'a'+1)];
        for(i=1;i&lt;=m;++i) cnt[i]+=cnt[i-1];
        for(i=n;i>=1;--i) sa[cnt[rk[i]]--]=i;
        for(w=1;;w&lt;&lt;=1,m=p)&#123;
            for(p=0,i=n;i>n-w;--i) id[++p]=i;
            for(i=1;i&lt;=n;++i)
            if(sa[i]>w) id[++p]=sa[i]-w;
            for(i=1;i&lt;=m;i++) cnt[i]=0;
            for(i=1;i&lt;=n;++i) ++cnt[px[i]=rk[id[i]]];
            for(i=1;i&lt;=m;++i) cnt[i]+=cnt[i-1];
            for(i=n;i>=1;--i) sa[cnt[px[i]]--]=id[i];
            for(i=1;i&lt;=n;i++) oldrk[i]=rk[i];
            for(p=0,i=1;i&lt;=n;++i)
            rk[sa[i]]=(oldrk[sa[i]]==oldrk[sa[i-1]]&amp;&amp;oldrk[sa[i]+w]==oldrk[sa[i-1]+w])?p:++p;
            if(p==n)&#123;
                for(i=1;i&lt;=n;++i) sa[rk[i]]=i;
                break;
            &#125;
        &#125;
    &#125;
    void buildheight()&#123;
        for(int i=1;i&lt;=n+1;++i) height[i]=h[i]=0;
        int k=0;
        for(int i=1;i&lt;=n;i++)&#123;
            if(rk[i]==1) continue;
            if(k) --k;
            int j=sa[rk[i]-1];
            while(j+k&lt;=n&amp;&amp;i+k&lt;=n&amp;&amp;s[i+k]==s[j+k]) k++;
            height[rk[i]]=k;
        &#125;
        for(int i=2;i&lt;=n;i++) lg[i]=lg[i>>1]+1;
        for(int i=1;i&lt;=n;i++) minn[0][i]=height[i];
        for(int j=1;(1&lt;&lt;j)&lt;=n;j++)
            for(int i=1;i+(1&lt;&lt;j)-1&lt;=n;i++) minn[j][i]=min(minn[j-1][i],minn[j-1][i+(1&lt;&lt;(j-1))]);
    &#125;
    int get_lcp(int l,int r)&#123;
        if(l==r) return n-l+1;
        l=rk[l],r=rk[r];
        if(l>r) swap(l,r);
        l++;
        int k=lg[r-l+1];
        return min(minn[k][l],minn[k][r-(1&lt;&lt;k)+1]);
    &#125;
&#125;sa;
struct tree&#123;
    int tot;
    int rt[N];
    int lc[N&lt;&lt;5];
    int rc[N&lt;&lt;5];
    int sum[N&lt;&lt;5];
    void cpy(int x,int y)&#123;
        lc[x]=lc[y];
        rc[x]=rc[y];
        sum[x]=sum[y];
    &#125;
    void build(int &amp;x,int l,int r)&#123;
        if(!x) x=++tot;
        sum[x]=0;
        if(l==r) return;
        int mid=l+r>>1;
        build(lc[x],l,mid);
        build(rc[x],mid+1,r);
        return;
    &#125;
    void update(int &amp;x,int pre,int l,int r,int pos)&#123;
        x=++tot;
        cpy(x,pre);
        if(l==r)&#123;
            sum[x]++;
            return;
        &#125;
        int mid=l+r>>1;
        if(pos&lt;=mid) update(lc[x],lc[pre],l,mid,pos);
        else update(rc[x],rc[pre],mid+1,r,pos);
        sum[x]=sum[lc[x]]+sum[rc[x]];
        return;
    &#125;
    int findr(int r1,int r2,int l,int r,int pos)&#123;
        if(l==r) return l;
        int res=-1;
        int mid=l+r>>1;
        if(mid>=pos&amp;&amp;sum[lc[r2]]-sum[lc[r1]]>0) res=findr(lc[r1],lc[r2],l,mid,pos);
        if(res!=-1) return res;
        if(sum[rc[r2]]-sum[rc[r1]]>0) res=findr(rc[r1],rc[r2],mid+1,r,pos);
        return res;
    &#125;
    int findl(int r1,int r2,int l,int r,int pos)&#123;
        if(l==r) return l;
        int res=-1;
        int mid=l+r>>1;
        if(mid+1&lt;=pos&amp;&amp;sum[rc[r2]]-sum[rc[r1]]>0) res=findl(rc[r1],rc[r2],mid+1,r,pos);
        if(res!=-1) return res;
        if(sum[lc[r2]]-sum[lc[r1]]>0) res=findl(lc[r1],lc[r2],l,mid,pos);
        return res;
    &#125;
&#125;t;

int check(int mid)&#123;
    int l=t.findl(t.rt[a-1],t.rt[b-mid+1],1,n,sa.rk[c]),
        r=t.findr(t.rt[a-1],t.rt[b-mid+1],1,n,sa.rk[c]);
    int res=0;
    if(l!=-1) res=max(res,sa.get_lcp(c,sa.sa[l]));
    if(r!=-1) res=max(res,sa.get_lcp(c,sa.sa[r]));
    return res>=mid;
&#125;

int main()&#123;
    ios::sync_with_stdio(0);
    cin.tie(0);cout.tie(0);

    cin>>n>>m;
    cin>>sa.s+1;
    sa.init(n,26);
    sa.buildsa();
    sa.buildheight();
    t.build(t.rt[0],1,n);
    for(int i=1;i&lt;=n;i++) t.update(t.rt[i],t.rt[i-1],1,n,sa.rk[i]);
    while(m--)&#123;
        cin>>a>>b>>c>>d;
        int l=0,r=min(b-a+1,d-c+1),ans=0;
        while(l&lt;=r)&#123;
            int mid=l+r>>1;
            if(check(mid)) ans=mid,l=mid+1;
            else r=mid-1;
        &#125;
        cout&lt;&lt;ans&lt;&lt;'\n';
    &#125;

    return 0;
&#125;
